import React, { useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './ChatDemo.css';

const featureItems = [
  {
    id: 'talk',
    label: '대화하기',
    short: '실시간 교감',
    tone: 'purple',
    route: '/chat',
    angle: -90,
    status: '대화 준비 완료',
    bubble: '안녕하세요. 오늘 기분은 어떤지 편하게 들려주세요.',
    options: ['오늘 조금 지쳤어요', '그냥 편하게 얘기하고 싶어요'],
    placeholder: '지금 마음을 한 줄로 적어보세요.',
  },
  {
    id: 'checkin',
    label: '오늘 체크인',
    short: '감정 입력',
    tone: 'yellow',
    route: '/dashboard',
    angle: -28,
    status: '체크인 모드',
    bubble: '오늘 하루는 어땠나요? 짧게라도 괜찮아요. 같이 정리해볼게요.',
    options: ['피곤함이 커요', '기분이 조금 가벼워요'],
    placeholder: '오늘 상태를 남겨보세요.',
  },
  {
    id: 'calendar',
    label: '감정 달력',
    short: '흐름 보기',
    tone: 'blue',
    route: '/dashboard/reports',
    angle: 34,
    status: '분석 모드',
    bubble: '이번 주에는 화요일과 금요일에 감정 기복이 조금 컸어요.',
    options: ['이번 주 흐름 보여줘', '특이한 날만 알려줘'],
    placeholder: '돌아보고 싶은 기간을 입력해보세요.',
  },
  {
    id: 'diary',
    label: '봇 일기',
    short: '기억 저장',
    tone: 'mint',
    route: '/dashboard/chat-history',
    angle: 96,
    status: '기억 정리 중',
    bubble: '오늘은 “조금 지쳤지만 잘 버텼다”는 느낌이 가장 크게 남아요.',
    options: ['오늘 일기 저장해줘', '한 줄 요약으로 정리해줘'],
    placeholder: '남기고 싶은 문장을 적어보세요.',
  },
  {
    id: 'report',
    label: '리포트',
    short: 'AI 요약',
    tone: 'pink',
    route: '/dashboard/reports',
    angle: 158,
    status: '리포트 생성 가능',
    bubble: '최근에는 수면과 회복 루틴을 함께 챙기면 더 좋아질 가능성이 보여요.',
    options: ['주간 리포트 열기', '추천 루틴 보기'],
    placeholder: '보고 싶은 인사이트를 입력해보세요.',
  },
  {
    id: 'custom',
    label: '꾸미기',
    short: '스타일 변경',
    tone: 'coral',
    route: '/dashboard/personal-settings',
    angle: 214,
    status: '커스터마이징 가능',
    bubble: '더 차분한 톤으로 이야기할까요, 아니면 조금 더 밝게 반응할까요?',
    options: ['조금 더 귀엽게', '차분한 톤으로 변경'],
    placeholder: '원하는 캐릭터 분위기를 적어보세요.',
  },
  {
    id: 'settings',
    label: '설정',
    short: '개인화 관리',
    tone: 'slate',
    route: '/dashboard/security-settings',
    angle: 270,
    status: '설정 관리',
    bubble: '원하는 대화 템포와 알림 강도를 설정해두면 더 편하게 이용할 수 있어요.',
    options: ['알림 조금 줄여줘', '대화 템포를 느리게'],
    placeholder: '바꾸고 싶은 설정을 입력해보세요.',
  },
];

function SparkleIcon() {
  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <path d="M12 2.5l1.9 5.1 5.1 1.9-5.1 1.9L12 16.5l-1.9-5.1-5.1-1.9 5.1-1.9L12 2.5z" />
      <path d="M18.5 14.5l.9 2.1 2.1.9-2.1.9-.9 2.1-.9-2.1-2.1-.9 2.1-.9.9-2.1z" />
    </svg>
  );
}

function TalkIcon() {
  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <path d="M5 6.5a3 3 0 0 1 3-3h8a3 3 0 0 1 3 3v5a3 3 0 0 1-3 3h-3.4L8.4 18a1 1 0 0 1-1.4-.9v-2.6A3 3 0 0 1 5 11.5v-5z" />
    </svg>
  );
}

function CheckIcon() {
  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <path d="M7 12.5l3.1 3.1L17.5 8.2" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round" />
      <path d="M12 21a9 9 0 1 0 0-18 9 9 0 0 0 0 18z" fill="none" stroke="currentColor" strokeWidth="1.8" />
    </svg>
  );
}

function CalendarIcon() {
  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <path d="M7 3.5v3M17 3.5v3M5.5 8.5h13M6.5 5.5h11a2 2 0 0 1 2 2v10a2.5 2.5 0 0 1-2.5 2.5h-10A2.5 2.5 0 0 1 4.5 17.5v-10a2 2 0 0 1 2-2z" fill="none" stroke="currentColor" strokeWidth="1.9" strokeLinecap="round" />
    </svg>
  );
}

function DiaryIcon() {
  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <path d="M7 4.5h9a2.5 2.5 0 0 1 2.5 2.5v11.5H8.2A2.2 2.2 0 0 0 6 20.7V6.5A2 2 0 0 1 8 4.5z" fill="none" stroke="currentColor" strokeWidth="1.9" />
      <path d="M8.5 9h7M8.5 12h7M8.5 15h4.5" fill="none" stroke="currentColor" strokeWidth="1.7" strokeLinecap="round" />
    </svg>
  );
}

function ReportIcon() {
  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <path d="M6 18.5V11M12 18.5V7M18 18.5v-4" fill="none" stroke="currentColor" strokeWidth="2.1" strokeLinecap="round" />
      <path d="M4 20h16" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" />
    </svg>
  );
}

function CustomizeIcon() {
  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <path d="M12 3.5l1.7 3.5 3.8.6-2.7 2.7.7 3.8L12 12.8 8.5 14.1l.7-3.8-2.7-2.7 3.8-.6L12 3.5z" />
      <circle cx="17.8" cy="17.8" r="2.6" fill="none" stroke="currentColor" strokeWidth="1.8" />
    </svg>
  );
}

function SettingsIcon() {
  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <path d="M12 8.3A3.7 3.7 0 1 0 12 15.7 3.7 3.7 0 0 0 12 8.3z" fill="none" stroke="currentColor" strokeWidth="1.8" />
      <path d="M19.1 13.1l1.2-1.1-1.3-2.2-1.6.2a6.3 6.3 0 0 0-1.1-.6l-.5-1.6h-2.6l-.5 1.6c-.4.2-.8.3-1.1.6l-1.6-.2-1.3 2.2 1.2 1.1a6 6 0 0 0 0 1.8l-1.2 1.1 1.3 2.2 1.6-.2c.3.2.7.4 1.1.6l.5 1.6h2.6l.5-1.6c.4-.2.8-.4 1.1-.6l1.6.2 1.3-2.2-1.2-1.1c.1-.3.1-.6.1-.9s0-.6-.1-.9z" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinejoin="round" />
    </svg>
  );
}

function SendIcon() {
  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <path
        d="M4 11.5L19 4l-3.8 16-4.1-5-4.9-1.1L4 11.5z"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.8"
        strokeLinejoin="round"
      />
    </svg>
  );
}

const iconMap = {
  talk: <TalkIcon />,
  checkin: <CheckIcon />,
  calendar: <CalendarIcon />,
  diary: <DiaryIcon />,
  report: <ReportIcon />,
  custom: <CustomizeIcon />,
  settings: <SettingsIcon />,
};

export default function ChatDemo() {
  const navigate = useNavigate();
  const [hubOpen, setHubOpen] = useState(false);
  const [activeId, setActiveId] = useState('talk');
  const [panelInput, setPanelInput] = useState('');

  const activeFeature = useMemo(
    () => featureItems.find((item) => item.id === activeId) || featureItems[0],
    [activeId]
  );

  const handleCharacterClick = () => {
    setHubOpen((prev) => !prev);
  };

  const handleFeatureSelect = (id) => {
    setHubOpen(true);
    setActiveId(id);
    const next = featureItems.find((item) => item.id === id);
    setPanelInput(next?.options?.[0] || '');
  };

  const handleStart = () => {
    if (activeFeature?.route) navigate(activeFeature.route);
  };

  return (
    <section className="virtualhub-section" id="character-hub">
      <div className="virtualhub-bg virtualhub-bg--one" />
      <div className="virtualhub-bg virtualhub-bg--two" />
      <div className="virtualhub-bg virtualhub-bg--three" />

      <div className="virtualhub-container">
        <div className="virtualhub-heading">
          <span className="virtualhub-kicker">
            <SparkleIcon />
            Virtual Character Experience
          </span>

          <h2>
            카톡형 채팅이 아니라,
            <br />
            <strong>화면에 나타난 캐릭터와 직접 대화하는 느낌</strong>
          </h2>

          <p>
            캐릭터를 클릭하면 주변 기능이 펼쳐지고,
            <br />
            선택한 기능에 맞춰 말풍선, 선택지, 입력창이 바로 반응합니다.
          </p>
        </div>

        <div className="virtualhub-stage-wrap">
          <div className="virtualhub-stage-card">
            <div className="virtualhub-stage-grid">
              <div className="virtualhub-stage">
                <div className={`virtualhub-orbit ${hubOpen ? 'is-open' : ''}`}>
                  {featureItems.map((item, index) => {
                    const isActive = activeId === item.id;
                    const style = {
                      '--node-angle': `${item.angle}deg`,
                      '--node-delay': `${index * 40}ms`,
                    };

                    return (
                      <button
                        key={item.id}
                        type="button"
                        className={`virtualhub-node virtualhub-node--${item.tone} ${
                          isActive ? 'is-active' : ''
                        } ${hubOpen ? 'is-visible' : ''}`}
                        style={style}
                        onClick={() => handleFeatureSelect(item.id)}
                        aria-label={item.label}
                      >
                        <span className="virtualhub-node__icon">{iconMap[item.id]}</span>
                        <span className="virtualhub-node__text">
                          <strong>{item.label}</strong>
                          <small>{item.short}</small>
                        </span>
                      </button>
                    );
                  })}

                  <div className={`virtualhub-character-shell ${hubOpen ? 'is-awake' : ''}`}>
                    <button
                      type="button"
                      className="virtualhub-character"
                      onClick={handleCharacterClick}
                      aria-label="버추얼 캐릭터 허브 열기"
                    >
                      <div className="virtualhub-character__halo" />
                      <div className="virtualhub-character__ring" />

                      <div className={`virtualhub-avatar virtualhub-avatar--${activeFeature.tone}`}>
                        <div className="virtualhub-avatar__face">
                          <span className="eye left" />
                          <span className="eye right" />
                          <span className={`mouth mood-${activeFeature.id}`} />
                        </div>
                        <div className="virtualhub-avatar__cheek left" />
                        <div className="virtualhub-avatar__cheek right" />
                      </div>

                      <div className="virtualhub-character__base">
                        <strong>AI Companion</strong>
                        <span>{activeFeature.status}</span>
                      </div>
                    </button>

                    <div className={`virtualhub-bubble ${hubOpen ? 'is-visible' : ''}`}>
                      <span className="virtualhub-bubble__badge">{activeFeature.label}</span>
                      <p>{activeFeature.bubble}</p>
                    </div>
                  </div>
                </div>

                <div className="virtualhub-mobile-grid">
                  {featureItems.map((item) => {
                    const isActive = activeId === item.id;
                    return (
                      <button
                        key={`mobile-${item.id}`}
                        type="button"
                        className={`virtualhub-mobile-card virtualhub-mobile-card--${item.tone} ${
                          isActive ? 'is-active' : ''
                        }`}
                        onClick={() => handleFeatureSelect(item.id)}
                      >
                        <span className="virtualhub-mobile-card__icon">{iconMap[item.id]}</span>
                        <span className="virtualhub-mobile-card__body">
                          <strong>{item.label}</strong>
                          <small>{item.short}</small>
                        </span>
                      </button>
                    );
                  })}
                </div>
              </div>

              <aside className={`virtualhub-live-panel virtualhub-live-panel--${activeFeature.tone}`}>
                <div className="virtualhub-live-panel__top">
                  <div>
                    <span className="virtualhub-live-panel__badge">{activeFeature.label}</span>
                    <h3>캐릭터와 이렇게 상호작용해요</h3>
                  </div>

                  <div className="virtualhub-live-panel__status">
                    <span className="dot" />
                    기능 선택됨
                  </div>
                </div>

                <div className="virtualhub-live-card">
                  <div className="virtualhub-live-card__header">
                    <div className="virtualhub-live-card__profile">
                      <div className={`virtualhub-live-card__avatar virtualhub-live-card__avatar--${activeFeature.tone}`}>
                        하
                      </div>
                      <div className="virtualhub-live-card__profile-text">
                        <strong>하루</strong>
                        <span>{activeFeature.short}</span>
                      </div>
                    </div>

                    <span className="virtualhub-live-card__chip">{activeFeature.status}</span>
                  </div>

                  <div className="virtualhub-live-stage">
                    <div className={`virtualhub-live-character virtualhub-live-character--${activeFeature.tone}`}>
                      <div className="virtualhub-live-character__halo" />
                      <div className="virtualhub-live-character__head">
                        <span className="eye left" />
                        <span className="eye right" />
                        <span className={`mouth mood-${activeFeature.id}`} />
                        <span className="cheek left" />
                        <span className="cheek right" />
                      </div>
                      <div className="virtualhub-live-character__body" />
                    </div>

                    <div className="virtualhub-live-bubble">
                      <strong>하루</strong>
                      <p>{activeFeature.bubble}</p>
                    </div>
                  </div>

                  <div className="virtualhub-live-choices">
                    {activeFeature.options.map((option) => (
                      <button
                        key={option}
                        type="button"
                        className="virtualhub-live-choice"
                        onClick={() => setPanelInput(option)}
                      >
                        {option}
                      </button>
                    ))}
                  </div>

                  <div className="virtualhub-live-input">
                    <input
                      type="text"
                      value={panelInput}
                      onChange={(e) => setPanelInput(e.target.value)}
                      placeholder={activeFeature.placeholder}
                    />
                    <button type="button" aria-label="메시지 전송">
                      <SendIcon />
                    </button>
                  </div>

                  <div className="virtualhub-live-tags">
                    <span>표정 변화</span>
                    <span>선택지 응답</span>
                    <span>직접 입력</span>
                  </div>
                </div>

                <div className="virtualhub-actions">
                  <button
                    type="button"
                    className="virtualhub-btn virtualhub-btn--primary"
                    onClick={handleStart}
                  >
                    이 기능 시작하기
                  </button>

                  <button
                    type="button"
                    className="virtualhub-btn virtualhub-btn--soft"
                    onClick={handleCharacterClick}
                  >
                    {hubOpen ? '옵션 접기' : '캐릭터 깨우기'}
                  </button>
                </div>
              </aside>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
